function subarraysWithSum(arr, k) {
  const result = [];
  const sumMap = new Map();
  sumMap.set(0, [-1]); // Handle subarrays starting from index 0

  let sum = 0;
  for (let i = 0; i < arr.length; i++) {
    sum += arr[i];

    if (sumMap.has(sum - k)) {
      for (const start of sumMap.get(sum - k)) {
        result.push([start + 1, i]);
      }
    }

    if (!sumMap.has(sum)) sumMap.set(sum, []);
    sumMap.get(sum).push(i);
  }

  return result;
}
